const healthData = $('Get Health Data').all();
const emailData = $('Get Important Emails').all();
const pastDecisions = $('Get Past Decisions').all();

const date = new Date().toISOString().split('T')[0];

const projects = [
  { name: 'sihlhack', url: 'https://sihlhack.ch', status: 'online', priority: 1 },
  { name: 'reaswiss', url: 'https://reaswiss.ch', status: 'online', priority: 2 },
  { name: 'bioco', url: 'https://bioco.ch', status: 'online', priority: 3 },
  { name: 'version.gmbh', url: 'https://version.gmbh', status: 'online', priority: 4 },
  { name: 'sihliconvalley', url: 'https://sihliconvalley.ch', status: 'online', priority: 5 },
  { name: 'badenleg', url: 'https://badenleg.ch', status: 'online', priority: 6 },
  { name: 'therapylist', url: 'https://therapylist.ch', status: 'offline', note: 'not online yet', priority: 7 },
  { name: 'qv-alststadt', url: 'https://qv-alststadt.ch', status: 'offline', note: 'not online yet', priority: 8 }
];

const briefing = {
  date,
  meeting_number: Math.ceil((new Date() - new Date('2025-01-01')) / (7 * 24 * 60 * 60 * 1000)),
  projects,
  infrastructure: {
    total_checks: healthData.length,
    incidents: healthData.filter(h => h.json.down_count > 0).length,
    sites_monitored: healthData[0]?.json?.total_sites || 0
  },
  communications: {
    total_important: emailData.length,
    urgent: emailData.filter(e => e.json.priority === 'urgent').length,
    action_required: emailData.filter(e => e.json.action_required).length,
    by_project: {}
  },
  recent_decisions: pastDecisions.map(d => ({
    date: d.json.created_at,
    topic: d.json.topic,
    decision: d.json.decision,
    status: d.json.status
  })),
  raw: {
    health: healthData.map(h => h.json),
    emails: emailData.map(e => ({
      subject: e.json.subject,
      from: e.json.from_address,
      summary: e.json.summary,
      priority: e.json.priority,
      project: e.json.project
    }))
  }
};

emailData.forEach(e => {
  const proj = e.json.project || 'general';
  briefing.communications.by_project[proj] = (briefing.communications.by_project[proj] || 0) + 1;
});

return [{ json: briefing }];

