parameters.jsCode:
const briefing = $('Compile Board Briefing').item.json;
const oa = $('Board Synthesis (OpenAI)').item.json;
const cl = $('Board Synthesis (Claude)').item.json;

const oaContent = oa.choices?.[0]?.message?.content || '';
const clContent = Array.isArray(cl.content) ? cl.content.map(c => c.text || '').join('\n') : (cl.content?.[0]?.text || cl.content || '');

let parsedOA = {};
let parsedCL = {};
try { parsedOA = JSON.parse(oaContent); } catch (_) { parsedOA = { summary: oaContent }; }
try { parsedCL = JSON.parse(clContent); } catch (_) { parsedCL = { summary: clContent }; }

const dedupe = (arr = []) => {
  const seen = new Set();
  const out = [];
  for (const item of arr) {
    const topic = (item.topic || '').toLowerCase();
    if (topic && seen.has(topic)) continue;
    if (topic) seen.add(topic);
    out.push(item);
  }
  return out;
};

const decisions = dedupe([...(parsedOA.decisions || []), ...(parsedCL.decisions || [])]);

const section = (title, val) => {
  if (!val) return `### ${title}\n- n/a`;
  if (Array.isArray(val)) return `### ${title}\n` + val.map(v => `- ${typeof v === 'string' ? v : JSON.stringify(v)}`).join('\n');
  if (typeof val === 'string') return `### ${title}\n${val}`;
  return `### ${title}\n` + Object.entries(val).map(([k,v]) => `- ${k}: ${v}`).join('\n');
};

const projectLines = briefing.projects
  .map(p => `- ${p.name}: ${p.status}${p.note ? ' (' + p.note + ')' : ''}`)
  .join('\n');

let minutes = `# Sihliconvalley Board Meeting #${briefing.meeting_number}\n`;
minutes += `**Date:** ${briefing.date} | **Time:** 14:00 Zurich\n\n`;
minutes += `## Projects & Status\n${projectLines}\n\n`;
minutes += `## Board Summary (OpenAI)\n`;
minutes += section('Summary', parsedOA.summary) + '\n\n';
minutes += section('Portfolio Strategist', parsedOA.portfolio) + '\n\n';
minutes += section('Delivery & Reliability', parsedOA.delivery) + '\n\n';
minutes += section('Product & Customer', parsedOA.product) + '\n\n';
minutes += section('Finance & Ops', parsedOA.finance) + '\n\n';
minutes += section('Compliance & Trust', parsedOA.compliance) + '\n\n';
minutes += `## Board Summary (Claude)\n`;
minutes += section('Summary', parsedCL.summary) + '\n\n';
minutes += section('Portfolio Strategist', parsedCL.portfolio) + '\n\n';
minutes += section('Delivery & Reliability', parsedCL.delivery) + '\n\n';
minutes += section('Product & Customer', parsedCL.product) + '\n\n';
minutes += section('Finance & Ops', parsedCL.finance) + '\n\n';
minutes += section('Compliance & Trust', parsedCL.compliance) + '\n\n';
minutes += '## Decisions to confirm\n';
if (decisions.length === 0) {
  minutes += '- None captured; add manually.\n';
} else {
  minutes += decisions.map(d => `- ${d.topic || 'topic'}: ${d.decision || 'decision'}${d.rationale ? ' (' + d.rationale + ')' : ''}`).join('\n') + '\n';
}
minutes += '\n---\n\n*Minutes generated automatically by Sihliconvalley Brain*\n';
minutes += '*Next meeting: next Wednesday 14:00*\n';

return [{ json: { minutes, briefing, responses: { openai: parsedOA, claude: parsedCL, raw: { openai: oa, claude: cl } } } }];

const scoreModel = (data) => {
  if (!data) return { score: 0, reasons: ['missing'] };
  const keys = ['summary','portfolio','delivery','product','finance','compliance'];
  let score = 0;
  const reasons = [];
  for (const k of keys) {
    const val = data[k];
    if (!val) { reasons.push(`${k}: missing`); continue; }
    const len = typeof val === 'string' ? val.length : Array.isArray(val) ? val.length : Object.keys(val || {}).length;
    score += Math.min(3, Math.max(1, len ? 1 : 0));
  }
  const decCount = Array.isArray(data.decisions) ? data.decisions.length : 0;
  score += decCount * 0.5;
  return { score: Number(score.toFixed(2)), reasons };
};

const oaScore = scoreModel($json.responses?.openai);
const clScore = scoreModel($json.responses?.claude);

let winner = 'tie';
if (oaScore.score > clScore.score + 0.25) winner = 'openai';
else if (clScore.score > oaScore.score + 0.25) winner = 'claude';

return [{ json: { ...$json, score: { openai: oaScore, claude: clScore, winner } } }];
